import{c as a,Q as i,j as t,m as s}from"./chunks/framework.rlpw0eGz.js";const u=JSON.parse('{"title":"WPF Dashboard Architecture Guide","description":"","frontmatter":{},"headers":[],"relativePath":"Dashboard_Architecture.md","filePath":"Dashboard_Architecture.md"}'),o={name:"Dashboard_Architecture.md"};function n(r,e,l,h,d,c){return i(),t("div",null,[...e[0]||(e[0]=[s(`<h1 id="wpf-dashboard-architecture-guide" tabindex="-1">WPF Dashboard Architecture Guide <a class="header-anchor" href="#wpf-dashboard-architecture-guide" aria-label="Permalink to &quot;WPF Dashboard Architecture Guide&quot;">​</a></h1><p>As of version 5.0.0, <strong>Windows-Optimisations</strong> utilizes a native WPF (Windows Presentation Foundation) dashboard powered entirely by PowerShell, removing the need for external compilers or heavy dependencies.</p><p>This document serves as a developer blueprint for the dashboard internals.</p><h2 id="core-components" tabindex="-1">Core Components <a class="header-anchor" href="#core-components" aria-label="Permalink to &quot;Core Components&quot;">​</a></h2><p>The dashboard relies on a strict separation of concerns:</p><ol><li><strong><code>GUI/Dashboard.xaml</code> (The View)</strong> This file contains pure XML markup. It defines the layout, grids, buttons, colors, and visual logic (like <code>DropShadowEffect</code> hover animations). It contains <strong>zero</strong> execution logic.</li><li><strong><code>Launch_Dashboard.ps1</code> (The Controller)</strong> This script bootstraps the environment, loads the <code>PresentationFramework</code> assemblies, parses the XAML file, and maps the UI elements to PowerShell variables. It binds click events to the actual execution scripts located in the <code>Tweaks/</code> and <code>Core/</code> directories.</li></ol><h2 id="the-event-binding-flow" tabindex="-1">The Event Binding Flow <a class="header-anchor" href="#the-event-binding-flow" aria-label="Permalink to &quot;The Event Binding Flow&quot;">​</a></h2><p>If you are a developer looking to add a new button or tab to the dashboard, follow this flow:</p><h3 id="_1-add-the-ui-element-in-xaml" tabindex="-1">1. Add the UI Element in XAML <a class="header-anchor" href="#_1-add-the-ui-element-in-xaml" aria-label="Permalink to &quot;1. Add the UI Element in XAML&quot;">​</a></h3><p>Open <code>GUI/Dashboard.xaml</code>. Locate the appropriate Tab or Panel, and add your element. <strong>Critical Rule:</strong> You must assign it an <code>x:Name</code>. This is how PowerShell finds it.</p><div class="language-xml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">xml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">Button</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> x:Name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;BtnApplyMyNewTweak&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> Content</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Apply My Tweak&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> Style</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;{StaticResource ActionButton}&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/&gt;</span></span></code></pre></div><h3 id="_2-map-the-element-in-powershell" tabindex="-1">2. Map the Element in PowerShell <a class="header-anchor" href="#_2-map-the-element-in-powershell" aria-label="Permalink to &quot;2. Map the Element in PowerShell&quot;">​</a></h3><p>Open <code>Launch_Dashboard.ps1</code>. Find the &quot;Map WPF Elements to PowerShell Variables&quot; region.</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$BtnApplyMyNewTweak </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> $Window.FindName(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;BtnApplyMyNewTweak&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><h3 id="_3-bind-the-logic" tabindex="-1">3. Bind the Logic <a class="header-anchor" href="#_3-bind-the-logic" aria-label="Permalink to &quot;3. Bind the Logic&quot;">​</a></h3><p>Further down in <code>Launch_Dashboard.ps1</code>, bind the click event to your execution script.</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$BtnApplyMyNewTweak.Add_Click({</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    Write-Host</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Running new tweak...&quot;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    &amp;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">$PSScriptRoot</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">\\Tweaks\\YourCategory\\YourScript.ps1&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">})</span></span></code></pre></div><h2 id="performance-telemetry-observability" tabindex="-1">Performance &amp; Telemetry (Observability) <a class="header-anchor" href="#performance-telemetry-observability" aria-label="Permalink to &quot;Performance &amp; Telemetry (Observability)&quot;">​</a></h2><p>The dashboard features an &quot;Observability&quot; tab that streams live system telemetry. We achieve this without freezing the UI thread by using efficient <code>.NET</code> classes rather than slow WMI calls:</p><ul><li><strong>CPU:</strong> <code>[System.Diagnostics.PerformanceCounter]</code></li><li><strong>RAM:</strong> <code>GlobalMemoryStatusEx</code> via inline C# P/Invoke.</li><li><strong>Uptime:</strong> <code>[Environment]::TickCount64</code></li></ul><p>These metrics are updated via a <code>System.Windows.Threading.DispatcherTimer</code> set to a 1000ms tick interval.</p><h2 id="why-xaml-over-winforms" tabindex="-1">Why XAML over WinForms? <a class="header-anchor" href="#why-xaml-over-winforms" aria-label="Permalink to &quot;Why XAML over WinForms?&quot;">​</a></h2><p>WinForms is legacy, blocking, and difficult to style dynamically. WPF allows us to use sophisticated layout grids (<code>Grid.RowDefinitions</code>, <code>Grid.ColumnDefinitions</code>) and hardware-accelerated rendering effects (like DropShadows and Border radiuses) that look native to Windows 11 without requiring any extra dependencies.</p><h2 id="extending-the-dashboard" tabindex="-1">Extending the Dashboard <a class="header-anchor" href="#extending-the-dashboard" aria-label="Permalink to &quot;Extending the Dashboard&quot;">​</a></h2><p>The <code>Launch_Dashboard.ps1</code> script is inherently extensible. If you need to build entirely new views, consider adding new <code>&lt;TabItem&gt;</code> elements within the main <code>&lt;TabControl&gt;</code>. Do not clutter the <code>Dashboard.xaml</code> with inline events (<code>Click=&quot;...&quot;</code>) because PowerShell&#39;s <code>XamlReader</code> cannot resolve inline code-behind without dynamic compilation. All events <strong>must</strong> be wired via <code>$Element.Add_Click({})</code> in the PowerShell runspace.</p>`,25)])])}const k=a(o,[["render",n]]);export{u as __pageData,k as default};
